module top_module(
    input a,
    input b,
    input sel_b1,
    input sel_b2,
    output out
);wire mux_out;
wire xor_out;

// 2-to-1 Mux
wire __mux_out_tmp = sel_b1 ? b : (sel_b2 ? a : 1'b0);
assign mux_out = __mux_out_tmp;

// XOR Gate
assign xor_out = a ^ b;

// Output
assign out = sel_b1 | sel_b2 ? mux_out : xor_out;

endmodule
